201→                'sfuser_id' => $summary->sfuser_id,
202→                'week_start' => $summary->week_start,
203→                'week_end' => $summary->week_end,
204→                'content' => $summary->content,
205→                'submit_days' => $summary->submit_days,
206→                'total_chars' => $summary->total_chars,
