229→        $weekEnd = $request->input('week_end');
230→        $targetName = $request->input('target_name', '');
231→
232→        // 解压 gzip+base64（同 DailyReportAiController::ask 的解压逻辑）
233→        if (str_starts_with($reportContext, 'gz:')) {
234→            $decoded = base64_decode(substr($reportContext, 3), true);
235→            $reportContext = $decoded !== false ? (gzdecode($decoded) ?: $reportContext) : $reportContext;
236→        }
237→        $reportContext = preg_replace('/\n{3,}/', "\n\n", trim($reportContext));
238→
239→        $systemPrompt = sprintf(self::WEEKLY_SUMMARY_PROMPT, $targetName, $weekStart, $weekEnd);
240→
241→        \Log::info('[lbl][0423-周摘要][Generate] request', [
242→            'sfuser_id' => $sfuserId,
243→            'week_start' => $weekStart,
244→            'target_name' => $targetName,
245→            'context_chars' => mb_strlen($reportContext),
246→        ]);
247→
248→        return $this->responseJsonSuccess([
249→            'content' => $reportContext,
250→            'ai_analysis_config' => [
251→                'system_prompt' => $systemPrompt,
252→                'target_field' => 'content',
253→            ],
254→        ]);
255→    }
