289→    public function saveProjects(Request $request): JsonResponse
290→    {
291→        $currentSfuserId = Arr::get($request->input('sfuser_info'), 'id');
292→        if (!DailyReportService::inAiWhitelist($currentSfuserId)) {
293→            return $this->responseJsonFail('无权限');
294→        }
295→
296→        $sfuserId = $request->input('sfuser_id');
297→        $weekStart = $request->input('week_start');
298→        $projectNames = $request->input('project_names', []);
299→
300→        $service = WeeklySummaryService::app();
301→        $roomsCreated = 0;
302→        $tunnelsUpdated = 0;
303→
304→        foreach ($projectNames as $name) {
305→            $name = trim($name);
306→            if (empty($name)) {
307→                continue;
308→            }
309→
310→            $existsBefore = DailyReportAiRoom::where('project_name', $name)->exists();
311→            $roomId = $service->findOrCreateRoom($name);
312→            if ($roomId <= 0) {
313→                continue;
314→            }
315→
316→            if (!$existsBefore) {
317→                $roomsCreated++;
318→            }
319→
320→            $service->saveTunnel($roomId, $sfuserId, $weekStart);
321→            $tunnelsUpdated++;
322→        }
323→
324→        \Log::info('[lbl][0423-周摘要][SaveProjects] done', [
325→            'sfuser_id' => $sfuserId,
326→            'week_start' => $weekStart,
327→            'projects' => count($projectNames),
328→            'rooms_created' => $roomsCreated,
329→            'tunnels_updated' => $tunnelsUpdated,
330→        ]);
331→
332→        return $this->responseJsonSuccess([
333→            'rooms_created' => $roomsCreated,
334→            'tunnels_updated' => $tunnelsUpdated,
335→        ]);
336→    }
