520→    public function ask(Request $request): JsonResponse
521→    {
522→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
523→        if (!DailyReportService::inAiWhitelist($sfuserId)) {
524→            \Log::info('[lbl][0416-AI日报][AiAsk] 无权限', ['sfuser_id' => $sfuserId]);
525→            return $this->responseJsonFail('无权限');
526→        }
527→        $roleId = $request->input('role_id');
528→        $sessionId = $request->input('session_id');
529→        $message = $request->input('message');
530→        $reportContext = $request->input('report_context', '');
531→        $reportContextRaw = $request->input('report_context_raw', '');
532→
533→        // 解压 report_context（前端 gzip+base64 压缩后以 "gz:" 前缀标识）
534→        if (str_starts_with($reportContext, 'gz:')) {
535→            $decoded = base64_decode(substr($reportContext, 3), true);
536→            $reportContext = $decoded !== false ? (gzdecode($decoded) ?: $reportContext) : $reportContext;
537→        }
538→        // 去除多余空白（连续空行压缩为单空行），减少发给 AI 的 token
539→        $reportContext = preg_replace('/\n{3,}/', "\n\n", trim($reportContext));
540→        \Log::info('[lbl][0416-AI日报][AiAsk] report_context size', [
541→            'bytes' => strlen($reportContext),
542→            'chars' => mb_strlen($reportContext),
543→        ]);
544→
545→        // 校验角色归属
546→        $role = DB::table('daily_report_ai_roles')
547→            ->where('id', $roleId)
548→            ->where('sfuser_id', $sfuserId)
549→            ->whereNull('deleted_at')
550→            ->first();
551→
552→        if (!$role) {
553→            return $this->responseJsonFail('角色不存在');
554→        }
555→
556→        // 创建或复用会话
557→        if (!$sessionId) {
558→            $title = mb_substr($message, 0, 20);
559→            $sessionId = DB::table('daily_report_ai_sessions')->insertGetId([
560→                'sfuser_id' => $sfuserId,
561→                'role_id' => $roleId,
562→                'title' => $title,
563→                'created_at' => now(),
564→                'updated_at' => now(),
565→            ]);
566→        } else {
567→            $sessionRow = DB::table('daily_report_ai_sessions')
568→                ->where('id', $sessionId)
569→                ->where('sfuser_id', $sfuserId)
570→                ->whereNull('deleted_at')
571→                ->first();
572→            if (!$sessionRow) {
573→                return $this->responseJsonFail('会话不存在');
574→            }
575→        }
576→
577→        // 解压 report_context_raw（与 report_context 相同的 gzip+base64 压缩格式）
578→        if (str_starts_with($reportContextRaw, 'gz:')) {
579→            $decoded = base64_decode(substr($reportContextRaw, 3), true);
580→            $reportContextRaw = $decoded !== false ? (gzdecode($decoded) ?: $reportContextRaw) : $reportContextRaw;
581→        }
582→
583→        // 保存同步日报上下文（如果有）—— 优先存原始 HTML，便于页面回显
584→        $contextToStore = !empty($reportContextRaw) ? $reportContextRaw : $reportContext;
585→        if (!empty($contextToStore)) {
586→            DB::table('daily_report_ai_messages')->insert([
587→                'session_id' => $sessionId,
588→                'role' => 'context',
589→                'content' => $contextToStore,
590→                'created_at' => now(),
591→            ]);
592→        }
593→
594→        // 保存用户消息
595→        DB::table('daily_report_ai_messages')->insert([
596→            'session_id' => $sessionId,
597→            'role' => 'user',
598→            'content' => $message,
599→            'created_at' => now(),
600→        ]);
601→
602→        // 更新会话时间
603→        DB::table('daily_report_ai_sessions')
604→            ->where('id', $sessionId)
605→            ->update(['updated_at' => now()]);
606→
607→        // 构建发送给 AI 的内容
608→        $queryParts = [];
609→        if (!empty($reportContext)) {
610→            $queryParts[] = "[日报数据]\n{$reportContext}";
611→        }
612→        $queryParts[] = $message;
613→        $query = implode("\n\n---\n\n", $queryParts);
614→
615→        \Log::info('[lbl][0416-AI日报][AiAsk] request', [
616→            'session' => $sessionId,
617→            'query_len' => mb_strlen($query),
618→        ]);
619→
620→        // 返回 query + session_id，AI streaming 由 oa-core TransferRequestService 完成
621→        return $this->responseJsonSuccess([
622→            'query' => $query,
623→            'session_id' => $sessionId,
624→        ]);
625→    }
